import React, { useState } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';

const NewsContainer = styled.div`
  max-width: 1400px;
  margin: 0 auto;
  padding: 1rem 0;
`;

const PageHeader = styled(motion.div)`
  margin-bottom: 4rem;

  h1 {
    font-size: 3.5rem;
    font-weight: 900;
    letter-spacing: -2px;
    margin-bottom: 1rem;
    background: ${props => props.theme.colors.accentPrimary};
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
  }

  p {
    color: ${props => props.theme.colors.textSecondary};
    font-size: 1.1rem;
    max-width: 600px;
  }
`;

const GlassCard = styled(motion.div)`
  background: ${props => props.theme.colors.cardBackground};
  border-radius: ${props => props.theme.borderRadius.large};
  border: 1px solid ${props => props.theme.colors.border};
  backdrop-filter: blur(12px);
  box-shadow: ${props => props.theme.shadows.card};
  position: relative;
  overflow: hidden;
`;

const FeaturedSection = styled(GlassCard)`
  padding: 4rem;
  margin-bottom: 5rem;
  display: grid;
  grid-template-columns: 1.5fr 1fr;
  gap: 4rem;
  align-items: center;

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
    padding: 2.5rem;
    gap: 2rem;
  }

  &::after {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: 300px;
    height: 300px;
    background: radial-gradient(circle, ${props => props.theme.colors.info}10 0%, transparent 70%);
    z-index: -1;
  }
`;

const FeaturedTitle = styled.h2`
  color: ${props => props.theme.colors.textPrimary};
  margin-bottom: 1.5rem;
  font-size: 2.8rem;
  font-weight: 800;
  line-height: 1.1;
  letter-spacing: -1px;
`;

const FeaturedContent = styled.p`
  color: ${props => props.theme.colors.textSecondary};
  line-height: 1.6;
  margin-bottom: 2.5rem;
  font-size: 1.1rem;
`;

const FeaturedMeta = styled.div`
  display: flex;
  gap: 2rem;
  align-items: center;
`;

const MetaItem = styled.div`
  display: flex;
  align-items: center;
  gap: 0.6rem;
  color: ${props => props.theme.colors.textSecondary};
  font-size: 0.9rem;
  font-weight: 500;

  svg {
    color: ${props => props.theme.colors.info};
  }
`;

const ControlsContainer = styled.div`
  display: flex;
  flex-direction: column;
  gap: 2rem;
  margin-bottom: 4rem;
`;

const SearchBox = styled.div`
  position: relative;
  max-width: 500px;

  input {
    width: 100%;
    padding: 1.2rem 1.5rem 1.2rem 3.5rem;
    background: ${props => props.theme.colors.glass};
    border: 1px solid ${props => props.theme.colors.border};
    border-radius: ${props => props.theme.borderRadius.medium};
    color: ${props => props.theme.colors.textPrimary};
    font-size: 1rem;
    transition: ${props => props.theme.transitions.default};

    &:focus {
      outline: none;
      border-color: ${props => props.theme.colors.info}50;
      background: rgba(255, 255, 255, 0.05);
      box-shadow: 0 0 0 4px ${props => props.theme.colors.info}10;
    }
  }

  &::before {
    content: '🔍';
    position: absolute;
    left: 1.2rem;
    top: 50%;
    transform: translateY(-50%);
    font-size: 1.2rem;
    opacity: 0.5;
  }
`;

const CategoryList = styled.div`
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
`;

const CategoryTag = styled.button<{ active: boolean }>`
  padding: 0.6rem 1.4rem;
  background: ${props => props.active ? props.theme.colors.info + '15' : 'transparent'};
  color: ${props => props.active ? props.theme.colors.info : props.theme.colors.textSecondary};
  border: 1px solid ${props => props.active ? props.theme.colors.info + '30' : props.theme.colors.border};
  border-radius: ${props => props.theme.borderRadius.large};
  cursor: pointer;
  font-weight: 600;
  font-size: 0.85rem;
  transition: ${props => props.theme.transitions.fast};

  &:hover {
    border-color: ${props => props.theme.colors.info}50;
    color: ${props => props.theme.colors.textPrimary};
  }
`;

const NewsGrid = styled(motion.div)`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 2rem;

  @media (max-width: 1100px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const NewsCard = styled(GlassCard)`
  padding: 2rem;
  display: flex;
  flex-direction: column;
  height: 100%;
  transition: ${props => props.theme.transitions.default};
  cursor: pointer;

  &:hover {
    transform: translateY(-8px);
    border-color: ${props => props.theme.colors.info}30;
    background: rgba(255, 255, 255, 0.05);
  }
`;

const NewsBadge = styled.span`
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: ${props => props.theme.colors.info};
  margin-bottom: 1rem;
  display: block;
`;

const NewsTitle = styled.h3`
  font-size: 1.4rem;
  font-weight: 700;
  line-height: 1.3;
  margin-bottom: 1rem;
  color: ${props => props.theme.colors.textPrimary};
`;

const NewsSummary = styled.p`
  font-size: 0.95rem;
  color: ${props => props.theme.colors.textSecondary};
  line-height: 1.6;
  margin-bottom: 2rem;
  flex-grow: 1;
`;

const NewsFooter = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-top: 1.5rem;
  border-top: 1px solid ${props => props.theme.colors.border};

  .date {
    font-size: 0.85rem;
    color: ${props => props.theme.colors.textSecondary};
    font-weight: 500;
  }

  .read-more {
